Below is an example script that achieves what you are asking for in After Effects. This script assumes that there is a text layer called "01" with some styling that you want to retain. It reads each line of text from an imported text file, using "*****" as a separator for the different blocks of text. It then creates a new composition for each block of text, naming them "Text01", "Text02", and so on, and replaces the content of the text layer with each string.

Please remember to tailor the script according to your exact needs. For example, you may need to adjust the path of the text file, composition settings, and names according to your project.

```javascript
{
    // Specify the path to your text file here
    var textFilePath = "C:/path/to/your/text_file.txt";

    // Read the file and split content using the "*****" separator
    function readTextFile(filePath) {
        var file = new File(filePath);

        if (file.exists) {
            file.open('r');
            var content = file.read();
            file.close();
            return content.split("*****");
        } else {
            alert("File not found!");
            return [];
        }
    }

    // Main function
    function createCompositionsFromText(textFilePath) {
        var textBlocks = readTextFile(textFilePath);
        var compIndex = 1;

        // Loop over each text block
        for (var i = 0; i < textBlocks.length; i++) {
            var textBlock = textBlocks[i].trim(); // Remove whitespace
            if (textBlock.length > 0) {
                // Create a new composition
                var compName = "Text" + (compIndex < 10 ? "0" : "") + compIndex; // Ensure two digits
                var newComp = app.project.items.addComp(compName, 1920, 1080, 1, 30, 30);

                // Find the "01" text layer in the project
                var textLayer = newComp.layers.addText(textBlock);

                // If you have a prestyled text layer that you'd like to duplicate and use its styles, use the code below
                /*
                var sourceTextLayer = findLayerByName("01");
                if (sourceTextLayer) {
                    textLayer = sourceTextLayer.duplicate();
                    textLayer.moveToBeginning(newComp);
                    textLayer.text.sourceText.setValue(textBlock);
                }
                */

                // Increase the composition counter
                compIndex++;
            }
        }
    }

    // Helper function to find a layer by name
    function findLayerByName(name) {
        for (var i = 1; i <= app.project.numItems; i++) {
            if (app.project.item(i).name === name && app.project.item(i) instanceof TextLayer) {
                return app.project.item(i);
            }
        }
        return null;
    }

    // Execute the script
    app.beginUndoGroup("Create Comps From Text");
    createCompositionsFromText(textFilePath);
    app.endUndoGroup();
}

// Run the script
createCompositionsFromText(textFilePath);
```

