    // Specify the path to your text file here
    var textFilePath = 'C:/path/to/your/text_file.txt';
    var sourceCompName = '01'; // Name of the original composition with stylized text

    // Read the file and split content using the "*****" separator
    function readTextFile(filePath) {
        var file = new File(filePath);

        if (file.exists) {
            file.open('r');
            var content = file.read();
            file.close();
            return content.split('*****');
        } else {
            alert('File not found!');
            return [];
        }
    }

    // Function to duplicate the source composition and update the text
    function duplicateAndUpdateComp(sourceComp, newText, compIndex) {
        var duplicatedComp = sourceComp.duplicate();
        duplicatedComp.name = "Text" + (compIndex < 10 ? '0' : '') + compIndex;

        // Find and update the text layer inside the duplicated composition
        for (var i = 1; i <= duplicatedComp.numLayers; i++) {
            if (duplicatedComp.layer(i).name === '01' && duplicatedComp.layer(i) instanceof TextLayer) {
                duplicatedComp.layer(i).text.sourceText.setValue(newText);
                break;
            }
        }

        return duplicatedComp;
    }

    // Main function
    function createCompsFromText(textFilePath) {
        var sourceComp = app.project.items.findItem(function(item) {
            return item.name === sourceCompName && item instanceof CompItem;
        });

        if (!sourceComp) {
            alert("Can't find a composition named '" + sourceCompName + "'");
            return;
        }

        var textBlocks = readTextFile(textFilePath);
        var compIndex = 1;

        // Loop over each text block
        app.beginUndoGroup('Create Comps From Text');
        textBlocks.forEach(function (textBlock) {
            textBlock = textBlock.trim(); // Remove whitespace
            if (textBlock) {
                duplicateAndUpdateComp(sourceComp, textBlock, compIndex++);
            }
        });
        app.endUndoGroup();
    }

    // Run the script
    createCompsFromText(textFilePath);
}
```
